#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline long long Min(long long x,long long y){return x<y?x:y;}
inline int Max(int x,int y){return x>y?x:y;}
const int N=5e5+10;
int n,k,a[N],sn[N];long long dp[N];
inline bool check(int m)
{
	dp[0]=0;rep(2,n,i)
	{
		long long tmp=dp[i-2]+a[i]-a[i-1]-m;
		if(dp[i-1]<tmp)dp[i]=dp[i-1],sn[i]=sn[i-1];
		else if(dp[i-1]>tmp)dp[i]=tmp,sn[i]=sn[i-2]+1;
		else dp[i]=tmp,sn[i]=Max(sn[i-1],sn[i-2]+1); 
	}
	return sn[n]>=k;
}
inline void Solve()
{
	n=read();k=read();rep(1,n,i)a[i]=read();
	long long l=0,r=a[n]-a[1],res=0,mid;while(l<=r)check(mid=(l+r)>>1)?(r=mid-1,res=mid):(l=mid+1);
	check(res);printf("%lld\n",dp[n]+1ll*res*k);return;
}
int main()
{
	int T=read();while(T--)Solve();return 0;
}
